import React, { useState } from 'react';
import { SearchIcon, CalendarIcon, LocationMarkerIcon, UserGroupIcon, FilterIcon } from '@heroicons/react/outline';

const Events = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [showFilters, setShowFilters] = useState(false);

  const [events, setEvents] = useState([
    {
      id: 1,
      title: 'Alumni Meet 2024',
      description: 'Join us for the biggest alumni reunion of the year. Connect with old friends and make new ones.',
      date: '2024-03-15',
      time: '10:00 AM',
      location: 'MVSR Campus, Hyderabad',
      type: 'meetup',
      image: '/api/placeholder/400/250',
      attendees: 245,
      maxAttendees: 500,
      registered: true
    },
    {
      id: 2,
      title: 'Career Fair 2024',
      description: 'Connect with top companies and explore exciting career opportunities. Open to all alumni and students.',
      date: '2024-04-20',
      time: '9:00 AM',
      location: 'Online',
      type: 'career',
      image: '/api/placeholder/400/250',
      attendees: 180,
      maxAttendees: 1000,
      registered: false
    },
    {
      id: 3,
      title: 'Tech Summit 2024',
      description: 'A technology conference featuring industry leaders and innovators. Learn about the latest tech trends.',
      date: '2024-05-10',
      time: '9:00 AM',
      location: 'Hyderabad Convention Center',
      type: 'conference',
      image: '/api/placeholder/400/250',
      attendees: 320,
      maxAttendees: 500,
      registered: false
    },
    {
      id: 4,
      title: 'Workshop: AI & Machine Learning',
      description: 'Hands-on workshop on artificial intelligence and machine learning fundamentals and applications.',
      date: '2024-03-25',
      time: '2:00 PM',
      location: 'MVSR Campus',
      type: 'workshop',
      image: '/api/placeholder/400/250',
      attendees: 45,
      maxAttendees: 60,
      registered: true
    },
    {
      id: 5,
      title: 'Startup Networking Night',
      description: 'Connect with fellow entrepreneurs and investors. Share ideas and explore collaboration opportunities.',
      date: '2024-04-05',
      time: '6:00 PM',
      location: 'Hyderabad',
      type: 'networking',
      image: '/api/placeholder/400/250',
      attendees: 78,
      maxAttendees: 100,
      registered: false
    },
    {
      id: 6,
      title: 'Alumni Awards Ceremony',
      description: 'Annual awards ceremony recognizing outstanding achievements of MVSR alumni across various fields.',
      date: '2024-06-15',
      time: '6:00 PM',
      location: 'MVSR Campus',
      type: 'ceremony',
      image: '/api/placeholder/400/250',
      attendees: 150,
      maxAttendees: 300,
      registered: false
    }
  ]);

  const filteredEvents = events.filter(event => {
    const matchesSearch = event.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         event.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || event.type === filterType;
    return matchesSearch && matchesType;
  });

  const eventTypes = [
    { value: 'all', label: 'All Events' },
    { value: 'meetup', label: 'Meetups' },
    { value: 'career', label: 'Career' },
    { value: 'conference', label: 'Conferences' },
    { value: 'workshop', label: 'Workshops' },
    { value: 'networking', label: 'Networking' },
    { value: 'ceremony', label: 'Ceremonies' }
  ];

  const getTypeColor = (type) => {
    const colors = {
      meetup: 'bg-blue-100 text-blue-800',
      career: 'bg-green-100 text-green-800',
      conference: 'bg-purple-100 text-purple-800',
      workshop: 'bg-yellow-100 text-yellow-800',
      networking: 'bg-pink-100 text-pink-800',
      ceremony: 'bg-red-100 text-red-800'
    };
    return colors[type] || 'bg-gray-100 text-gray-800';
  };

  const handleRegister = (eventId) => {
    setEvents(events.map(event => 
      event.id === eventId 
        ? { ...event, registered: !event.registered, attendees: event.registered ? event.attendees - 1 : event.attendees + 1 }
        : event
    ));
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">
            Alumni Events
          </h1>
          <p className="text-xl text-gray-600 max-w-3xl mx-auto">
            Stay connected with your alma mater through exciting events and reunions
          </p>
        </div>

        {/* Search and Filters */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-8">
          <div className="flex flex-col lg:flex-row gap-4 mb-4">
            <div className="flex-1">
              <div className="relative">
                <SearchIcon className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search events..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-mvsr-500 focus:border-transparent"
                />
              </div>
            </div>
            <div className="flex gap-4">
              <select
                value={filterType}
                onChange={(e) => setFilterType(e.target.value)}
                className="px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-mvsr-500 focus:border-transparent"
              >
                {eventTypes.map(type => (
                  <option key={type.value} value={type.value}>{type.label}</option>
                ))}
              </select>
              <button
                onClick={() => setShowFilters(!showFilters)}
                className="px-6 py-3 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors duration-200 flex items-center justify-center"
              >
                <FilterIcon className="h-5 w-5 mr-2" />
                More Filters
              </button>
            </div>
          </div>

          <div className="flex items-center justify-between">
            <p className="text-gray-600">
              Showing <span className="font-semibold">{filteredEvents.length}</span> events
            </p>
          </div>
        </div>

        {/* Events Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredEvents.map((event) => (
            <div key={event.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow duration-200">
              <img 
                src={event.image} 
                alt={event.title}
                className="w-full h-48 object-cover"
              />
              <div className="p-6">
                <div className="flex items-center justify-between mb-4">
                  <span className={`px-3 py-1 rounded-full text-xs font-medium ${getTypeColor(event.type)}`}>
                    {event.type}
                  </span>
                  <div className="flex items-center text-sm text-gray-500">
                    <UserGroupIcon className="h-4 w-4 mr-1" />
                    {event.attendees}/{event.maxAttendees}
                  </div>
                </div>

                <h3 className="text-xl font-semibold text-gray-900 mb-2">
                  {event.title}
                </h3>
                
                <p className="text-gray-600 mb-4 line-clamp-2">
                  {event.description}
                </p>

                <div className="space-y-2 mb-4">
                  <div className="flex items-center text-gray-600">
                    <CalendarIcon className="h-4 w-4 mr-2 text-gray-400" />
                    <span className="text-sm">
                      {new Date(event.date).toLocaleDateString()} at {event.time}
                    </span>
                  </div>
                  <div className="flex items-center text-gray-600">
                    <LocationMarkerIcon className="h-4 w-4 mr-2 text-gray-400" />
                    <span className="text-sm">{event.location}</span>
                  </div>
                </div>

                <div className="flex gap-2">
                  <button
                    onClick={() => handleRegister(event.id)}
                    className={`flex-1 px-4 py-2 rounded-lg font-medium transition-colors duration-200 ${
                      event.registered
                        ? 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                        : 'bg-mvsr-600 text-white hover:bg-mvsr-700'
                    }`}
                  >
                    {event.registered ? 'Registered' : 'Register Now'}
                  </button>
                  <button className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors duration-200">
                    Learn More
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredEvents.length === 0 && (
          <div className="text-center py-12">
            <CalendarIcon className="h-16 w-16 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">
              No events found
            </h3>
            <p className="text-gray-600">
              Try adjusting your search or filters to find more events
            </p>
          </div>
        )}

        {/* Event Calendar Preview */}
        <div className="mt-16 bg-white rounded-lg shadow-md p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Event Calendar</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="text-center">
              <h3 className="font-semibold text-gray-900 mb-4">March 2024</h3>
              <div className="space-y-2">
                <div className="p-3 bg-mvsr-50 rounded-lg">
                  <p className="text-sm font-medium text-mvsr-600">Mar 15</p>
                  <p className="text-sm text-gray-700">Alumni Meet 2024</p>
                </div>
                <div className="p-3 bg-gray-50 rounded-lg">
                  <p className="text-sm font-medium text-gray-600">Mar 25</p>
                  <p className="text-sm text-gray-700">AI Workshop</p>
                </div>
              </div>
            </div>
            
            <div className="text-center">
              <h3 className="font-semibold text-gray-900 mb-4">April 2024</h3>
              <div className="space-y-2">
                <div className="p-3 bg-gray-50 rounded-lg">
                  <p className="text-sm font-medium text-gray-600">Apr 5</p>
                  <p className="text-sm text-gray-700">Startup Networking</p>
                </div>
                <div className="p-3 bg-mvsr-50 rounded-lg">
                  <p className="text-sm font-medium text-mvsr-600">Apr 20</p>
                  <p className="text-sm text-gray-700">Career Fair 2024</p>
                </div>
              </div>
            </div>
            
            <div className="text-center">
              <h3 className="font-semibold text-gray-900 mb-4">May 2024</h3>
              <div className="space-y-2">
                <div className="p-3 bg-mvsr-50 rounded-lg">
                  <p className="text-sm font-medium text-mvsr-600">May 10</p>
                  <p className="text-sm text-gray-700">Tech Summit</p>
                </div>
                <div className="p-3 bg-gray-50 rounded-lg">
                  <p className="text-sm font-medium text-gray-600">Jun 15</p>
                  <p className="text-sm text-gray-700">Awards Ceremony</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Events;
