import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import AlumniDirectory from './pages/AlumniDirectory';
import AlumniDirectoryEnhanced from './pages/AlumniDirectoryEnhanced';
import Events from './pages/Events';
import News from './pages/News';
import Gallery from './pages/Gallery';
import Careers from './pages/Careers';
import Academics from './pages/Academics';
import Departments from './pages/Departments';
import StudentLife from './pages/StudentLife';
import HelpDesk from './pages/HelpDesk';
import Contact from './pages/Contact';
import LoginEnhanced from './pages/LoginEnhanced';
import LoginDemo from './pages/LoginDemo';
import RegisterEnhanced from './pages/RegisterEnhanced';
import Dashboard from './pages/Dashboard';
import Profile from './pages/Profile';
import OAuthCallback from './pages/OAuthCallback';
import ProtectedRoute from './components/ProtectedRoute';

function App() {
  return (
    <Router>
      <div className="min-h-screen flex flex-col">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/alumni" element={<AlumniDirectory />} />
            <Route path="/alumni-enhanced" element={<AlumniDirectoryEnhanced />} />
            <Route path="/events" element={<Events />} />
            <Route path="/news" element={<News />} />
            <Route path="/gallery" element={<Gallery />} />
            <Route path="/careers" element={<Careers />} />
            <Route path="/academics" element={<Academics />} />
            <Route path="/student-life" element={<StudentLife />} />
            <Route path="/departments" element={<Departments />} />
            <Route path="/help-desk" element={<HelpDesk />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/login" element={<LoginEnhanced />} />
            <Route path="/login-demo" element={<LoginDemo />} />
            <Route path="/register" element={<RegisterEnhanced />} />
            <Route path="/auth/success" element={<OAuthCallback />} />
            <Route path="/auth/error" element={<OAuthCallback />} />
            <Route 
              path="/dashboard" 
              element={
                <ProtectedRoute>
                  <Dashboard />
                </ProtectedRoute>
              } 
            />
            <Route 
              path="/profile" 
              element={
                <ProtectedRoute>
                  <Profile />
                </ProtectedRoute>
              } 
            />
            <Route 
              path="*" 
              element={
                <div className="min-h-screen bg-gray-50 py-8">
                  <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center">
                      <h1 className="text-4xl font-bold text-gray-900 mb-4">Page Not Found</h1>
                      <p className="text-xl text-gray-600 mb-8">The page you're looking for doesn't exist.</p>
                      <a 
                        href="/" 
                        className="inline-block px-6 py-3 bg-mvsr-600 text-white rounded-lg hover:bg-mvsr-700 transition-colors duration-200"
                      >
                        Go Home
                      </a>
                    </div>
                  </div>
                </div>
              } 
            />
          </Routes>
        </main>
        <Footer />
        <Toaster 
          position="top-right"
          toastOptions={{
            duration: 4000,
            style: {
              background: '#363636',
              color: '#fff',
            },
            success: {
              duration: 3000,
              iconTheme: {
                primary: '#0ea5e9',
                secondary: '#fff',
              },
            },
            error: {
              duration: 5000,
              iconTheme: {
                primary: '#ef4444',
                secondary: '#fff',
              },
            },
          }}
        />
      </div>
    </Router>
  );
}

export default App;
